                        yield return PathDrivePrefixOnWindows;
                        if (searchOption == SearchOption.AllDirectories)
                        {
                            await foreach (var subPath in EnumeratePathsAsyncImpl(PathDrivePrefixOnWindows, searchPattern, searchOption, searchTarget, cancellationToken: cancellationToken).WithCancellation(cancellationToken).ConfigureAwait(false))
                            {
                                yield return subPath;
                            }
                        }
                    }

                    yield break;
                }

                // When listing for /drive, return the list of drives available
                if (path == PathDrivePrefixOnWindows)
                {
                    var pathDrives = new List<UPath>();
                    foreach (var drive in DriveInfo.GetDrives())
                    {
                        if (drive.Name.Length < 2 || drive.Name[1] != ':')
                        {
                            continue;
                        }

                        var pathDrive = PathDrivePrefixOnWindows / char.ToLowerInvariant(drive.Name[0]).ToString();
                        if (search.Match(pathDrive))
                        {
                            pathDrives.Add(pathDrive);
                            if (searchForDirectory)
                            {
                                yield return pathDrive;
                            }
                        }
                    }

                    if (searchOption == SearchOption.AllDirectories)
                    {
                        foreach (var pathDrive in pathDrives)
                        {
                            await foreach (var subPath in EnumeratePathsAsyncImpl(pathDrive, searchPattern, searchOption, searchTarget, cancellationToken: cancellationToken).WithCancellation(cancellationToken).ConfigureAwait(false))
                            {
                                yield return subPath;
                            }
