        IEnumerable<string> results;
        switch (searchTarget)
        {
            case SearchTarget.File:
                results = Directory.EnumerateFiles(await ConvertPathToInternalAsync(path, cancellationToken: cancellationToken).ConfigureAwait(false), searchPattern, searchOption);
                break;
            case SearchTarget.Directory:
