            _watcher.Changed += async (sender, args) => Changed?.Invoke(this, await RemapAsync(args).ConfigureAwait(false));
            _watcher.Created += async (sender, args) => Created?.Invoke(this, await RemapAsync(args).ConfigureAwait(false));
            _watcher.Deleted += async (sender, args) => Deleted?.Invoke(this, await RemapAsync(args).ConfigureAwait(false));
            _watcher.Error += async (sender, args) => Error?.Invoke(this, await RemapAsync(args).ConfigureAwait(false));
            _watcher.Renamed += async (sender, args) => Renamed?.Invoke(this, await RemapAsync(args).ConfigureAwait(false));
        }

        ~Watcher()
        {
            Dispose(false);
        }

        public void Dispose()
        {
            Dispose(true);
            GC.SuppressFinalize(this);
        }

        private void Dispose(bool disposing)
        {
            if (disposing)
            {
                _watcher.Dispose();
            }
        }

        private async ValueTask<FileChangedEventArgsAsync> RemapAsync(FileSystemEventArgs args, CancellationToken cancellationToken = default)
        {
            var newChangeType = (WatcherChangeTypes)args.ChangeType;
            var newPath = await _fileSystem.ConvertPathFromInternalAsync(args.FullPath, cancellationToken: cancellationToken).ConfigureAwait(false);
            return new FileChangedEventArgsAsync(FileSystem, newChangeType, newPath);
        }

        private async ValueTask<FileSystemErrorEventArgsAsync> RemapAsync(ErrorEventArgs args, CancellationToken cancellationToken = default)
        {
            return new FileSystemErrorEventArgsAsync(args.GetException());
        }

        private async ValueTask<FileRenamedEventArgsAsync> RemapAsync(RenamedEventArgs args, CancellationToken cancellationToken = default)
        {
            var newChangeType = (WatcherChangeTypes)args.ChangeType;
            var newPath = await _fileSystem.ConvertPathFromInternalAsync(args.FullPath, cancellationToken: cancellationToken).ConfigureAwait(false);
            var newOldPath = await _fileSystem.ConvertPathFromInternalAsync(args.OldFullPath, cancellationToken: cancellationToken).ConfigureAwait(false);
            return new FileRenamedEventArgsAsync(FileSystem, newChangeType, newPath, newOldPath);
        }
    }

    /// <inheritdoc/>
    protected override async ValueTask<System.String> ConvertPathToInternalAsyncImpl(UPath path, CancellationToken cancellationToken)
    {
        var absolutePath = path.FullName;
        if (IsOnWindows)
        {
            if (!absolutePath.StartsWith(DrivePrefixOnWindows, StringComparison.Ordinal) || absolutePath.Length == DrivePrefixOnWindows.Length || !IsDriveLetter(absolutePath[DrivePrefixOnWindows.Length]))
                throw new ArgumentException($"A path on Windows must start by `{DrivePrefixOnWindows}` followed by the drive letter");
            var driveLetter = char.ToUpper(absolutePath[DrivePrefixOnWindows.Length]);
            if (absolutePath.Length != DrivePrefixOnWindows.Length + 1 && absolutePath[DrivePrefixOnWindows.Length + 1] != UPath.DirectorySeparator)
                throw new ArgumentException($"The driver letter `/{DrivePrefixOnWindows}{absolutePath[DrivePrefixOnWindows.Length]}` must be followed by a `/` or nothing in the path -> `{absolutePath}`");
            var builder = UPath.GetSharedStringBuilder();
            builder.Append(driveLetter).Append(":\\");
            if (absolutePath.Length > DrivePrefixOnWindows.Length + 1)
                builder.Append(absolutePath.Replace(UPath.DirectorySeparator, '\\').Substring(DrivePrefixOnWindows.Length + 2));
            return builder.ToString();
        }

        return absolutePath;
    }

    /// <inheritdoc/>
    protected override async ValueTask<Zio.UPath> ConvertPathFromInternalAsyncImpl(string innerPath, CancellationToken cancellationToken)
    {
        if (IsOnWindows)
        {
            // We currently don't support special Windows files (\\.\ \??\  DosDevices...etc.)
            if (innerPath.StartsWith(@"\\", StringComparison.Ordinal) || innerPath.StartsWith(@"\?", StringComparison.Ordinal))
                throw new NotSupportedException($"Path starting with `\\\\` or `\\?` are not supported -> `{innerPath}` ");
            // We want to avoid using Path.GetFullPath unless absolutely necessary,
            // because it can change the case of already rooted paths that contain a ~
            var absolutePath = HasWindowsVolumeLabel(innerPath) ? innerPath : Path.GetFullPath(innerPath);
            // Assert that Path.GetFullPath returned the format we expect
            if (!HasWindowsVolumeLabel(absolutePath))
                throw new ArgumentException($"Expecting a drive for the path `{absolutePath}`");
            var builder = UPath.GetSharedStringBuilder();
            builder.Append(DrivePrefixOnWindows).Append(char.ToLowerInvariant(absolutePath[0])).Append('/');
            if (absolutePath.Length > 2)
                builder.Append(absolutePath.Substring(2));
            return new UPath(builder.ToString());
        }

        return innerPath;
    }

    private static bool IsWithinSpecialDirectory(UPath path)
    {
        if (!IsOnWindows)
        {
            return false;
        }

        var parentDirectory = path.GetDirectory();
        return path == PathDrivePrefixOnWindows || path == UPath.Root || parentDirectory == PathDrivePrefixOnWindows || parentDirectory == UPath.Root;
    }

    private static bool SpecialDirectoryExists(UPath path)
    {
        // /drive or / can be read
        if (path == PathDrivePrefixOnWindows || path == UPath.Root)
        {
            return true;
        }

        // If /xxx, invalid (parent folder is /)
        var parentDirectory = path.GetDirectory();
        if (parentDirectory == UPath.Root)
        {
            return false;
        }

        var dirName = path.GetName();
        // Else check that we have a valid drive path (e.g /drive/c)
        return parentDirectory == PathDrivePrefixOnWindows && dirName.Length == 1 && DriveInfo.GetDrives().Any(p => char.ToLowerInvariant(p.Name[0]) == dirName[0]);
    }

    private static bool IsDriveLetter(char c)
    {
        return c >= 'a' && c <= 'z' || c >= 'A' && c <= 'Z';
    }

    private static bool HasWindowsVolumeLabel(string path)
    {
        if (!IsOnWindows)
            throw new NotSupportedException($"{nameof(HasWindowsVolumeLabel)} is only supported on Windows platforms.");
        return path.Length >= 3 && path[1] == ':' && path[2] is '\\' or '/';
    }
}
#endif
